'use client';

import { useCartStore } from '@/entities/cart/model/cartStore';
import { Button } from '@/components/ui/button';

export const CartWidget = () => {
  const { items, getTotalItems, getTotalPrice, clearCart } = useCartStore();

  return (
    <div className="p-4 border rounded-lg shadow-sm bg-white">
      <h2 className="text-lg font-semibold mb-4">Корзина</h2>
      {items.length === 0 ? (
        <p className="text-gray-500">Ваша корзина пуста</p>
      ) : (
        <div className="space-y-4">
          {items.map((item) => (
            <div key={item.id} className="flex justify-between items-center">
              <div>
                <p className="font-medium">{item.title}</p>
                <p className="text-sm text-gray-500">{item.quantity} x {item.price} ₽</p>
              </div>
              <p className="font-semibold">{item.quantity * item.price} ₽</p>
            </div>
          ))}
          <div className="border-t pt-4 mt-4">
            <div className="flex justify-between items-center mb-4">
              <span className="font-medium">Итого ({getTotalItems()} шт.):</span>
              <span className="font-bold text-lg">{getTotalPrice()} ₽</span>
            </div>
            <div className="flex gap-2">
              <Button variant="outline" onClick={clearCart} className="w-full">
                Очистить
              </Button>
              <Button className="w-full">
                Оформить
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
